import React, { useState, useEffect, useRef } from 'react';

function GifAnimationControlledByScroll({ gifSrc, scrollPercentage }) {
  const [gifFrames, setGifFrames] = useState([]);
  const imageRef = useRef(null);

  useEffect(() => {
    // Función para descomprimir el GIF en frames individuales
    function extractFramesFromGif(gifSrc) {
      return new Promise((resolve, reject) => {
        const gif = new Image();
        gif.onload = function() {
          const canvas = document.createElement('canvas');
          const ctx = canvas.getContext('2d');
          const frames = [];

          canvas.width = gif.width;
          canvas.height = gif.height;
          ctx.drawImage(gif, 0, 0);

          const frameCount = 100; // Número de frames de la animación

          for (let i = 0; i < frameCount; i++) {
            const imageData = ctx.getImageData(i * gif.width, 0, gif.width, gif.height);
            const tempCanvas = document.createElement('canvas');
            const tempCtx = tempCanvas.getContext('2d');

            tempCanvas.width = gif.width;
            tempCanvas.height = gif.height;
            tempCtx.putImageData(imageData, 0, 0);

            const frameDataURL = tempCanvas.toDataURL('image/webp');
            frames.push(frameDataURL);
          }

          resolve(frames);
        };

        gif.src = gifSrc;
      });
    }

    // Llama a la función para descomprimir el GIF y obtener los frames
    extractFramesFromGif(gifSrc).then(frames => {
      setGifFrames(frames);
    });
  }, [gifSrc]);

  const frameIndex = Math.floor((scrollPercentage / 100) * gifFrames.length);
  const currentFrameSrc = gifFrames[frameIndex];

  useEffect(() => {
    const image = imageRef.current;
    if (image && currentFrameSrc) {
      image.src = currentFrameSrc;
    }
  }, [currentFrameSrc]);

  return (
    <div className="GifAnimationControlledByScroll">
      <img ref={imageRef} alt="Animated GIF" style={{ width: '100%' }} />
    </div>
  );
}

export default GifAnimationControlledByScroll;
